import json
import os
from urllib.request import Request, urlopen

repo = (os.environ.get("GITHUB_REPO") or "").strip()
if not repo:
    return {"check_error": "GITHUB_REPO is not set in environment"}

token = (os.environ.get("GITHUB_TOKEN") or "").strip()
headers = {
    "Accept": "application/vnd.github+json",
    "X-GitHub-Api-Version": "2022-11-28",
    "User-Agent": "nanoclaw-pm-snippet",
}
if token:
    headers["Authorization"] = f"Bearer {token}"

seen_path = "/workspace/group/seen_issues.json"
if not os.path.exists(seen_path):
    with open(seen_path, "w", encoding="utf-8") as f:
        json.dump([], f, ensure_ascii=False, indent=2)

try:
    with open(seen_path, "r", encoding="utf-8") as f:
        raw_seen = json.load(f)
except Exception:
    raw_seen = []

seen_numbers = []
for value in raw_seen if isinstance(raw_seen, list) else []:
    try:
        seen_numbers.append(int(value))
    except Exception:
        continue
seen_set = set(seen_numbers)

try:
    request = Request(
        f"https://api.github.com/repos/{repo}/issues?state=open&per_page=100",
        headers=headers,
    )
    with urlopen(request, timeout=20) as response:
        raw_issues = json.loads(response.read().decode("utf-8"))
except Exception as err:
    return {
        "repo": repo,
        "checked_at": context.get("run_started_at"),
        "check_error": f"issue fetch failed: {err}",
        "new_issues": [],
        "all_open_issue_numbers": [],
        "seen_issue_numbers": sorted(seen_set),
        "seen_file_path": seen_path,
    }

issues = []
for issue in raw_issues if isinstance(raw_issues, list) else []:
    if not isinstance(issue, dict):
        continue
    if "pull_request" in issue:
        continue
    number = issue.get("number")
    if not isinstance(number, int):
        continue
    labels_raw = issue.get("labels") or []
    labels = []
    for label in labels_raw if isinstance(labels_raw, list) else []:
        if isinstance(label, dict) and isinstance(label.get("name"), str):
            labels.append(label["name"])
        elif isinstance(label, str):
            labels.append(label)
    issues.append({
        "number": number,
        "title": issue.get("title") or "",
        "body": issue.get("body") or "",
        "labels": labels,
        "state": issue.get("state") or "open",
        "url": issue.get("html_url") or "",
    })

all_open_numbers = sorted([issue["number"] for issue in issues])
new_issues = [issue for issue in issues if issue["number"] not in seen_set]

if not new_issues:
    return False

return {
    "repo": repo,
    "checked_at": context.get("run_started_at"),
    "new_issues": new_issues,
    "all_open_issue_numbers": all_open_numbers,
    "seen_issue_numbers": sorted(seen_set),
    "seen_file_path": seen_path,
}
